<?php
 namespace WPAICG\Core\Providers\Google\Methods; use WPAICG\Core\Providers\GoogleProviderStrategy; if (!defined('ABSPATH')) { exit; } function format_google_model_list_logic(GoogleProviderStrategy $strategyInstance, array $raw_models): array { $formatted = []; foreach ($raw_models as $model) { if (!is_array($model)) continue; $mId = $model['name'] ?? null; if (!empty($mId)) { $cleanId = (strpos($mId, 'models/') === 0) ? substr($mId, 7) : $mId; $supportedMethods = $model['supportedGenerationMethods'] ?? []; $formatted[] = [ 'id' => $cleanId, 'name' => $model['displayName'] ?? $cleanId, 'version' => $model['version'] ?? '', 'supportedGenerationMethods' => $supportedMethods, ]; } } return $formatted; }